import React, { useState, useEffect } from 'react';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const DriverDashboard = () => {
    const { user } = useAuth();
    const [assignedRides, setAssignedRides] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedRide, setSelectedRide] = useState(null);
    const [showAcceptModal, setShowAcceptModal] = useState(false);

    useEffect(() => {
        fetchAssignedRides();
    }, []);

    const fetchAssignedRides = async () => {
        try {
            const response = await api.get('/bookings/driver-bookings');
            setAssignedRides(response.data.data);
        } catch (error) {
            toast.error('Failed to fetch assigned rides');
        } finally {
            setLoading(false);
        }
    };

    const handleAcceptRide = async (rideId) => {
        try {
            await api.put(`/rides/${rideId}/status`, { status: 'active' });
            toast.success('Ride accepted successfully!');
            setShowAcceptModal(false);
            fetchAssignedRides();
        } catch (error) {
            toast.error('Failed to accept ride');
        }
    };

    const handleCompleteRide = async (rideId) => {
        try {
            await api.put(`/rides/${rideId}/status`, { status: 'completed' });
            toast.success('Ride completed! Payment will be processed.');
            fetchAssignedRides();
        } catch (error) {
            toast.error('Failed to complete ride');
        }
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center h-64">
                <div className="spinner"></div>
            </div>
        );
    }

    return (
        <div className="dashboard-container">
            <div className="dashboard-header">
                <h1 className="dashboard-title">Welcome, {user?.name}!</h1>
                <p className="dashboard-subtitle">Manage your assigned rides and track earnings</p>
            </div>

            {/* Stats Section */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <div className="stats-card">
                    <div className="stats-number">{assignedRides.length}</div>
                    <div className="stats-label">Total Assigned Rides</div>
                </div>
                <div className="stats-card">
                    <div className="stats-number">
                        {assignedRides.filter(r => r.status === 'active').length}
                    </div>
                    <div className="stats-label">Active Rides</div>
                </div>
                <div className="stats-card">
                    <div className="stats-number">
                        ₹{assignedRides
                            .filter(r => r.status === 'completed')
                            .reduce((sum, ride) => sum + (ride.totalEarnings || 0), 0)}
                    </div>
                    <div className="stats-label">Total Earnings</div>
                </div>
            </div>

            {/* Assigned Rides Section */}
            <div>
                <h2 className="text-2xl font-semibold mb-4">Your Assigned Rides</h2>
                <div className="space-y-4">
                    {assignedRides.map((ride) => (
                        <div key={ride._id} className="card fade-in">
                            <div className="card-body">
                                <div className="flex justify-between items-start">
                                    <div className="flex-1">
                                        <h3 className="text-lg font-semibold">{ride.routeName}</h3>
                                        <p className="text-sm text-gray-500 mt-1">
                                            {new Date(ride.departureTime).toLocaleString()}
                                        </p>
                                        <div className="mt-2 space-y-1">
                                            <p className="text-sm">
                                                <span className="font-medium">From:</span> {ride.pickupLocation?.address || 'Pickup location'}
                                            </p>
                                            <p className="text-sm">
                                                <span className="font-medium">To:</span> {ride.dropLocation?.address || 'Drop location'}
                                            </p>
                                            <p className="text-sm">
                                                <span className="font-medium">Passengers:</span> {ride.passengers?.length || 0} / {ride.availableSeats}
                                            </p>
                                            <p className="text-sm">
                                                <span className="font-medium">Total Fare:</span> ₹{ride.baseFare}
                                            </p>
                                        </div>
                                        <div className="mt-3">
                                            <span className={`badge ${
                                                ride.status === 'scheduled' ? 'badge-warning' :
                                                ride.status === 'active' ? 'badge-success' :
                                                ride.status === 'completed' ? 'badge-info' :
                                                'badge-danger'
                                            }`}>
                                                {ride.status?.toUpperCase()}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="ml-4">
                                        {ride.status === 'scheduled' && (
                                            <button
                                                onClick={() => {
                                                    setSelectedRide(ride);
                                                    setShowAcceptModal(true);
                                                }}
                                                className="btn-success px-4 py-2 rounded"
                                            >
                                                Accept Ride
                                            </button>
                                        )}
                                        {ride.status === 'active' && (
                                            <button
                                                onClick={() => handleCompleteRide(ride._id)}
                                                className="btn-primary px-4 py-2 rounded"
                                            >
                                                Complete Ride
                                            </button>
                                        )}
                                        {ride.status === 'completed' && (
                                            <div className="text-green-600 font-semibold">
                                                Completed ✓
                                            </div>
                                        )}
                                    </div>
                                </div>

                                {/* Passenger List */}
                                {ride.passengers && ride.passengers.length > 0 && (
                                    <div className="mt-4 pt-4 border-t">
                                        <h4 className="font-medium mb-2">Passengers:</h4>
                                        <div className="space-y-2">
                                            {ride.passengers.map((passenger, idx) => (
                                                <div key={idx} className="flex justify-between items-center text-sm">
                                                    <span>{passenger.user?.name || 'Passenger'}</span>
                                                    <span className="text-blue-600">₹{passenger.fare}</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                    {assignedRides.length === 0 && (
                        <div className="text-center py-8 text-gray-500">
                            <p>No rides assigned yet. Check back later!</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Accept Ride Modal */}
            {showAcceptModal && selectedRide && (
                <div className="modal-overlay" onClick={() => setShowAcceptModal(false)}>
                    <div className="modal-content p-6" onClick={(e) => e.stopPropagation()}>
                        <h3 className="text-xl font-bold mb-4">Accept Ride</h3>
                        <div className="mb-4">
                            <p><strong>Route:</strong> {selectedRide.routeName}</p>
                            <p><strong>Time:</strong> {new Date(selectedRide.departureTime).toLocaleString()}</p>
                            <p><strong>Passengers:</strong> {selectedRide.passengers?.length || 0}</p>
                            <p><strong>Total Fare:</strong> ₹{selectedRide.baseFare}</p>
                        </div>
                        <div className="flex justify-end space-x-3">
                            <button
                                onClick={() => setShowAcceptModal(false)}
                                className="btn-secondary px-4 py-2 rounded"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={() => handleAcceptRide(selectedRide._id)}
                                className="btn-success px-4 py-2 rounded"
                            >
                                Accept Ride
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default DriverDashboard;
